const [referenceNumber, setReferenceNumber] = useState('');
const [status, setStatus] = useState(null);
const [loading, setLoading] = useState(false);

const lookupStatus = async () => {
  setLoading(true);
  // In production: fetch from status-service API
  // Mock for prototype:
  setStatus({
    state: 'in-review',
    updatedAt: new Date().toISOString(),
    description: 'Your application is being reviewed by our team.'
  });
  setLoading(false);
};

const statusTypeMap = {
  'submitted': 'information',
  'in-review': 'information',
  'approved': 'success',
  'declined': 'emergency',
  'action-required': 'important'
};

return (
  <GoabOneColumnLayout>
    <GoabPageBlock width="704px">
      <h1>Check application status</h1>
      <p>Enter your reference number to see the current status of your application.</p>

      <GoabInput
        name="referenceNumber"
        value={referenceNumber}
        onChange={(_, value) => setReferenceNumber(value)}
        placeholder="e.g., APP-2026-12345"
      />
      <GoabButton onClick={lookupStatus} disabled={loading || !referenceNumber}>
        {loading ? 'Looking up...' : 'Check status'}
      </GoabButton>

      {status && (
        <>
          <GoabCallout type={statusTypeMap[status.state]} heading={status.state.replace('-', ' ')}>
            {status.description}
          </GoabCallout>
          <p><small>Last updated: {new Date(status.updatedAt).toLocaleDateString()}</small></p>
        </>
      )}
    </GoabPageBlock>
  </GoabOneColumnLayout>
);
